module RefModule (
    input clk,
    input load,
    input [4:0] initial_value,
    output reg [4:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    // 5-bit binary counter with loadable initial value logic
    always @(posedge clk) begin
        if (load) begin
            count <= initial_value;
        end else begin
            count <= count + 1;
        end
    end

endmodule
